INSERT INTO public.questions (skill_id, level, question_text, question_type, options, correct_answer, marks) VALUES
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What does HTML stand for?', 'mcq', '[{"text":"HyperText Markup Language","is_correct":true},{"text":"High Tech Modern Language","is_correct":false},{"text":"Hyper Transfer Markup Language","is_correct":false},{"text":"Home Tool Markup Language","is_correct":false}]', 'HyperText Markup Language', 1),
