('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag creates a list item?', 'mcq', '[{"text":"<li>","is_correct":true},{"text":"<list>","is_correct":false},{"text":"<item>","is_correct":false},{"text":"<ul>","is_correct":false}]', '<li>', 1),
