('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag creates a paragraph?', 'mcq', '[{"text":"<p>","is_correct":true},{"text":"<para>","is_correct":false},{"text":"<text>","is_correct":false},{"text":"<paragraph>","is_correct":false}]', '<p>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which element defines the body?', 'mcq', '[{"text":"<body>","is_correct":true},{"text":"<content>","is_correct":false},{"text":"<main>","is_correct":false},{"text":"<page>","is_correct":false}]', '<body>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag is used for line break?', 'mcq', '[{"text":"<br>","is_correct":true},{"text":"<lb>","is_correct":false},{"text":"<break>","is_correct":false},{"text":"<newline>","is_correct":false}]', '<br>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag creates a table?', 'mcq', '[{"text":"<table>","is_correct":true},{"text":"<tab>","is_correct":false},{"text":"<grid>","is_correct":false},{"text":"<tbl>","is_correct":false}]', '<table>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag is used for an unordered list?', 'mcq', '[{"text":"<ul>","is_correct":true},{"text":"<ol>","is_correct":false},{"text":"<list>","is_correct":false},{"text":"<dl>","is_correct":false}]', '<ul>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What does the alt attribute do on an image?', 'mcq', '[{"text":"Provides alternative text","is_correct":true},{"text":"Sets alignment","is_correct":false},{"text":"Defines the title","is_correct":false},{"text":"Adds a link","is_correct":false}]', 'Provides alternative text', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag defines a section in a document?', 'mcq', '[{"text":"<section>","is_correct":true},{"text":"<div>","is_correct":false},{"text":"<part>","is_correct":false},{"text":"<block>","is_correct":false}]', '<section>', 1),
