('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What is the purpose of the meta tag?', 'mcq', '[{"text":"Provides metadata about the document","is_correct":true},{"text":"Creates a menu","is_correct":false},{"text":"Defines a method","is_correct":false},{"text":"Adds multimedia","is_correct":false}]', 'Provides metadata about the document', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag is used for bold text?', 'mcq', '[{"text":"<strong>","is_correct":true},{"text":"<bold>","is_correct":false},{"text":"<b>","is_correct":false},{"text":"<em>","is_correct":false}]', '<strong>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What does the action attribute in form specify?', 'mcq', '[{"text":"Where to send form data","is_correct":true},{"text":"The form style","is_correct":false},{"text":"The form name","is_correct":false},{"text":"Input validation","is_correct":false}]', 'Where to send form data', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag embeds a video?', 'mcq', '[{"text":"<video>","is_correct":true},{"text":"<media>","is_correct":false},{"text":"<movie>","is_correct":false},{"text":"<embed>","is_correct":false}]', '<video>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What is a semantic HTML element?', 'mcq', '[{"text":"An element that describes its meaning","is_correct":true},{"text":"Any div element","is_correct":false},{"text":"A styled element","is_correct":false},{"text":"A JavaScript element","is_correct":false}]', 'An element that describes its meaning', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag defines a navigation section?', 'mcq', '[{"text":"<nav>","is_correct":true},{"text":"<navigation>","is_correct":false},{"text":"<menu>","is_correct":false},{"text":"<navbar>","is_correct":false}]', '<nav>', 1),
