('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag creates a dropdown list?', 'mcq', '[{"text":"<select>","is_correct":true},{"text":"<dropdown>","is_correct":false},{"text":"<list>","is_correct":false},{"text":"<option>","is_correct":false}]', '<select>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What is the canvas element used for?', 'mcq', '[{"text":"Drawing graphics via JavaScript","is_correct":true},{"text":"Displaying text","is_correct":false},{"text":"Creating forms","is_correct":false},{"text":"Embedding videos","is_correct":false}]', 'Drawing graphics via JavaScript', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which attribute uniquely identifies an element?', 'mcq', '[{"text":"id","is_correct":true},{"text":"class","is_correct":false},{"text":"name","is_correct":false},{"text":"key","is_correct":false}]', 'id', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What does the footer tag represent?', 'mcq', '[{"text":"Footer of a section or page","is_correct":true},{"text":"Bottom margin","is_correct":false},{"text":"A footnote","is_correct":false},{"text":"Copyright notice","is_correct":false}]', 'Footer of a section or page', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag defines a table row?', 'mcq', '[{"text":"<tr>","is_correct":true},{"text":"<row>","is_correct":false},{"text":"<td>","is_correct":false},{"text":"<th>","is_correct":false}]', '<tr>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What is the difference between div and span?', 'mcq', '[{"text":"div is block-level, span is inline","is_correct":true},{"text":"They are the same","is_correct":false},{"text":"span is block-level","is_correct":false},{"text":"div is inline","is_correct":false}]', 'div is block-level, span is inline', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which attribute specifies the language of the document?', 'mcq', '[{"text":"lang","is_correct":true},{"text":"language","is_correct":false},{"text":"locale","is_correct":false},{"text":"lng","is_correct":false}]', 'lang', 1),
