('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag creates a text input field?', 'mcq', '[{"text":"<input type=text>","is_correct":true},{"text":"<textfield>","is_correct":false},{"text":"<text>","is_correct":false},{"text":"<input type=string>","is_correct":false}]', '<input type=text>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What is the purpose of the aside element?', 'mcq', '[{"text":"Content tangentially related to the main content","is_correct":true},{"text":"A sidebar menu","is_correct":false},{"text":"An advertisement","is_correct":false},{"text":"A comment","is_correct":false}]', 'Content tangentially related to the main content', 1),
