('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What does the details tag do?', 'mcq', '[{"text":"Creates a collapsible disclosure widget","is_correct":true},{"text":"Shows metadata","is_correct":false},{"text":"Defines a description list","is_correct":false},{"text":"Creates a dialog","is_correct":false}]', 'Creates a collapsible disclosure widget', 1),
