('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag is used for emphasized text?', 'mcq', '[{"text":"<em>","is_correct":true},{"text":"<emphasis>","is_correct":false},{"text":"<italic>","is_correct":false},{"text":"<i>","is_correct":false}]', '<em>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What does the required attribute do?', 'mcq', '[{"text":"Makes a form field mandatory","is_correct":true},{"text":"Adds a red border","is_correct":false},{"text":"Sets focus","is_correct":false},{"text":"Validates email","is_correct":false}]', 'Makes a form field mandatory', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'Which tag groups related form elements?', 'mcq', '[{"text":"<fieldset>","is_correct":true},{"text":"<formgroup>","is_correct":false},{"text":"<group>","is_correct":false},{"text":"<inputgroup>","is_correct":false}]', '<fieldset>', 1),
('2e00e46a-5f94-4f93-b193-ed32adb3ebec', 1, 'What is the article element used for?', 'mcq', '[{"text":"Self-contained composition","is_correct":true},{"text":"A blog page","is_correct":false},{"text":"A paragraph","is_correct":false},{"text":"A section","is_correct":false}]', 'Self-contained composition', 1),
