INSERT INTO public.questions (skill_id, level, question_text, question_type, options, correct_answer, marks) VALUES
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'What does CSS stand for?', 'mcq', '[{"text":"Cascading Style Sheets","is_correct":true},{"text":"Creative Style Sheets","is_correct":false},{"text":"Computer Style Sheets","is_correct":false},{"text":"Colorful Style Sheets","is_correct":false}]', 'Cascading Style Sheets', 1),
