('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'How do you select an element by ID?', 'mcq', '[{"text":"#id","is_correct":true},{"text":".id","is_correct":false},{"text":"id:","is_correct":false},{"text":"*id","is_correct":false}]', '#id', 1),
