('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'How do you select elements by class?', 'mcq', '[{"text":".classname","is_correct":true},{"text":"#classname","is_correct":false},{"text":"classname:","is_correct":false},{"text":"*classname","is_correct":false}]', '.classname', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'Which display value hides an element?', 'mcq', '[{"text":"none","is_correct":true},{"text":"hidden","is_correct":false},{"text":"invisible","is_correct":false},{"text":"off","is_correct":false}]', 'none', 1),
