('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'Which unit is relative to viewport width?', 'mcq', '[{"text":"vw","is_correct":true},{"text":"pw","is_correct":false},{"text":"%w","is_correct":false},{"text":"rw","is_correct":false}]', 'vw', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'What is the CSS box model?', 'mcq', '[{"text":"Content, padding, border, margin","is_correct":true},{"text":"Header, body, footer","is_correct":false},{"text":"Div, span, p","is_correct":false},{"text":"Flex, grid, block","is_correct":false}]', 'Content, padding, border, margin', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'Which property sets the background image?', 'mcq', '[{"text":"background-image","is_correct":true},{"text":"bg-image","is_correct":false},{"text":"image","is_correct":false},{"text":"background-src","is_correct":false}]', 'background-image', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'What does z-index control?', 'mcq', '[{"text":"Stacking order of elements","is_correct":true},{"text":"Zoom level","is_correct":false},{"text":"Z-axis rotation","is_correct":false},{"text":"Height","is_correct":false}]', 'Stacking order of elements', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'Which property controls the space between lines?', 'mcq', '[{"text":"line-height","is_correct":true},{"text":"line-spacing","is_correct":false},{"text":"text-spacing","is_correct":false},{"text":"letter-spacing","is_correct":false}]', 'line-height', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'What is a CSS pseudo-class?', 'mcq', '[{"text":"A keyword added to a selector for a special state","is_correct":true},{"text":"A class in HTML","is_correct":false},{"text":"A JavaScript function","is_correct":false},{"text":"A media type","is_correct":false}]', 'A keyword added to a selector for a special state', 1),
