('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'Which property controls element overflow?', 'mcq', '[{"text":"overflow","is_correct":true},{"text":"scroll","is_correct":false},{"text":"clip","is_correct":false},{"text":"hide","is_correct":false}]', 'overflow', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'What is the difference between em and rem?', 'mcq', '[{"text":"em is relative to parent, rem to root","is_correct":true},{"text":"They are the same","is_correct":false},{"text":"rem is relative to parent","is_correct":false},{"text":"em is absolute","is_correct":false}]', 'em is relative to parent, rem to root', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'Which property creates CSS animations?', 'mcq', '[{"text":"animation","is_correct":true},{"text":"transition","is_correct":false},{"text":"transform","is_correct":false},{"text":"motion","is_correct":false}]', 'animation', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'What is a media query used for?', 'mcq', '[{"text":"Responsive design based on conditions","is_correct":true},{"text":"Playing media files","is_correct":false},{"text":"Querying databases","is_correct":false},{"text":"Loading images","is_correct":false}]', 'Responsive design based on conditions', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'Which property aligns items on the cross axis in flexbox?', 'mcq', '[{"text":"align-items","is_correct":true},{"text":"justify-content","is_correct":false},{"text":"flex-align","is_correct":false},{"text":"vertical-align","is_correct":false}]', 'align-items', 1),
