('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'Which selector targets the first child?', 'mcq', '[{"text":":first-child","is_correct":true},{"text":":first","is_correct":false},{"text":":initial","is_correct":false},{"text":":start","is_correct":false}]', ':first-child', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'What is CSS Grid?', 'mcq', '[{"text":"A two-dimensional layout system","is_correct":true},{"text":"A table system","is_correct":false},{"text":"A font system","is_correct":false},{"text":"A color system","is_correct":false}]', 'A two-dimensional layout system', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'Which property sets element width to include padding and border?', 'mcq', '[{"text":"box-sizing: border-box","is_correct":true},{"text":"width-mode: full","is_correct":false},{"text":"sizing: include-all","is_correct":false},{"text":"box-model: full","is_correct":false}]', 'box-sizing: border-box', 1),
