('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'Which property controls the gap between grid items?', 'mcq', '[{"text":"gap","is_correct":true},{"text":"grid-spacing","is_correct":false},{"text":"cell-gap","is_correct":false},{"text":"item-gap","is_correct":false}]', 'gap', 1),
('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'What is specificity in CSS?', 'mcq', '[{"text":"How the browser decides which rules apply","is_correct":true},{"text":"The speed of rendering","is_correct":false},{"text":"The order of stylesheets","is_correct":false},{"text":"The size of CSS file","is_correct":false}]', 'How the browser decides which rules apply', 1),
