('840d76c8-50c6-44c6-8676-1a980178aeaf', 1, 'What does transition property do?', 'mcq', '[{"text":"Smoothly animates property changes","is_correct":true},{"text":"Moves elements","is_correct":false},{"text":"Changes display type","is_correct":false},{"text":"Sets timing","is_correct":false}]', 'Smoothly animates property changes', 1),
